"use strict";(self.webpackChunkdst_api_webdocs=self.webpackChunkdst_api_webdocs||[]).push([["341048"],{463892(e){e.exports=JSON.parse('{"tag":{"label":"container","permalink":"/dst-api-webdocs/docs/tags/container","allTagsPath":"/dst-api-webdocs/docs/tags","count":32,"items":[{"id":"game-scripts/prefabs/alterguardianhatshard","title":"Alterguardianhatshard","description":"A portable light-emitting storage container that holds a single Mushroom Spore and adjusts its light colour and appearance based on the spore type.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/alterguardianhatshard"},{"id":"game-scripts/prefabs/battlesong_container","title":"Battlesong Container","description":"A portable container prefab that functions as storage with burnable behavior, custom open/close sounds, and inventory integration for Wigfrid\'s battlesong-themed items.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/battlesong_container"},{"id":"game-scripts/prefabs/beard_sack","title":"Beard Sack","description":"A wearable container prefab for Beardlings that opens on equip and closes on unequip, functioning as a special inventory slot in the Beard.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/beard_sack"},{"id":"game-scripts/prefabs/candybag","title":"Candybag","description":"A wearable container item that functions as a backpack with fire-sensitive locking behavior and Ashdrop mechanics.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/candybag"},{"id":"game-scripts/prefabs/chest_mimic","title":"Chest Mimic","description":"A transformable chest entity that hides as a loot chest and attacks players upon opening, functioning as both a container and a hostile monster.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/chest_mimic"},{"id":"game-scripts/scenarios/chestfunctions","title":"Chestfunctions","description":"Provides utility functions for spawning loot in containers and managing chest trap behaviors with randomization and event handling.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/chestfunctions"},{"id":"game-scripts/prefabs/collapsedchest","title":"Collapsedchest","description":"Acts as a destructible container structure that holds a nested chest and reconstructs into it upon completion, or drops its contents upon pick/hit if incomplete.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/collapsedchest"},{"id":"game-scripts/components/constructionbuilder","title":"Constructionbuilder","description":"Manages the construction state and UI container for a builder entity performing construction tasks.","permalink":"/dst-api-webdocs/docs/game-scripts/components/constructionbuilder"},{"id":"game-scripts/prefabs/container_opener","title":"Container opener","description":"Represents a lightweight, hidden entity that acts as a proxy reference link between a container and its opener, facilitating networked attachment and lifecycle synchronization.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/container_opener"},{"id":"game-scripts/components/container_proxy","title":"Container Proxy","description":"Acts as a proxy layer between a container\'s master entity and its openers, managing network synchronization and opener lifecycle for multiplayer consistency.","permalink":"/dst-api-webdocs/docs/game-scripts/components/container_proxy"},{"id":"game-scripts/components/containerinstallableitem","title":"Containerinstallableitem","description":"Manages installation and uninstallation behavior for items that can be placed into containers or wielded by entities.","permalink":"/dst-api-webdocs/docs/game-scripts/components/containerinstallableitem"},{"id":"game-scripts/prefabs/cookpot","title":"Cookpot","description":"Manages cooking state, interactions, and loot generation for the Crock Pot structure in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/cookpot"},{"id":"game-scripts/prefabs/elixir_container","title":"Elixir Container","description":"A portable storage container with three inventory slots, designed to hold items while being carried or opened by the player.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/elixir_container"},{"id":"game-scripts/prefabs/hutch","title":"Hutch","description":"Manages the Chester hutch entity, a companion that transforms between forms based on inventory batteries and provides light, damage reflection, and sanity effects.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/hutch"},{"id":"game-scripts/prefabs/klaus_sack","title":"Klaus Sack","description":"A interactible container prefab that triggers Klaus\'s summoning when unlocked with the correct key, and drops loot bundles upon opening.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/klaus_sack"},{"id":"game-scripts/prefabs/krampus_sack","title":"Krampus Sack","description":"A wearable container item that opens when equipped and closes when unequipped, providing inventory storage with water resistance.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/krampus_sack"},{"id":"game-scripts/prefabs/livingtree_halloween","title":"Livingtree Halloween","description":"Represents a dynamic, growable Halloween-themed tree entity that supports decoration, burning, and staged growth.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/livingtree_halloween"},{"id":"game-scripts/prefabs/oceanfishingrod","title":"Oceanfishingrod","description":"Implements the ocean fishing rod item, managing tackle slots, reticule targeting, and fishing state transitions in Don\'t Starve Together.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/oceanfishingrod"},{"id":"game-scripts/prefabs/piggyback","title":"Piggyback","description":"A wearable backpack item that provides limited container storage, increases walk speed, and offers no water resistance.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/piggyback"},{"id":"game-scripts/prefabs/pirate_stash","title":"Pirate Stash","description":"Acts as a buried container that holds loot (particularly blueprints), supports digging interaction, preserves items indefinitely, and manages loot distribution upon excavation.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pirate_stash"},{"id":"game-scripts/prefabs/pocketdimensioncontainers","title":"Pocketdimensioncontainers","description":"Creates and registers prefabs for pocket dimension storage containers with networked classified visibility logic.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/pocketdimensioncontainers"},{"id":"game-scripts/prefabs/portablecookpot","title":"Portablecookpot","description":"Manages the cooked pot\'s cooking state, container interaction, deployable behavior, and visual/sound feedback during cooking, burning, and dismantling.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/portablecookpot"},{"id":"game-scripts/prefabs/rabbitkinghorn_chest","title":"Rabbitkinghorn Chest","description":"A portable chest that stores items in the Rabbit King\'s horn pocket dimension and despawns after a fixed duration unless opened.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/rabbitkinghorn_chest"},{"id":"game-scripts/prefabs/seedpouch","title":"Seedpouch","description":"Acts as a wearable body-slot container that opens automatically when equipped and preserves items inside it.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/seedpouch"},{"id":"game-scripts/stategraphs/SGchester","title":"Sgchester","description":"Manages the state machine and animation logic for Chester, a mob that can open and close like a container, move via bouncing, and be transformed or devoured.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGchester"},{"id":"game-scripts/stategraphs/SGoceantrawler","title":"Sgoceantrawler","description":"Manages animation and sound playback states for the ocean trawler entity based on its state (e.g., idle, raised, lowered) and container contents.","permalink":"/dst-api-webdocs/docs/game-scripts/stategraphs/SGoceantrawler"},{"id":"game-scripts/prefabs/slingshotmodscontainer","title":"Slingshotmodscontainer","description":"Manages the UI container for the slingshot mod interface, handling sound playback and container lifecycle.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/slingshotmodscontainer"},{"id":"game-scripts/scenarios/sunkenchest_oceanmonument","title":"Sunkenchest Oceanmonument","description":"Defines loot configuration and initialization logic for ocean monument sunken chests in DST.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/sunkenchest_oceanmonument"},{"id":"game-scripts/prefabs/tacklecontainer","title":"Tacklecontainer","description":"Implements a portable, burnable storage container for the Hermit character with animated open/close states and integration into the container and inventory systems.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/tacklecontainer"},{"id":"game-scripts/scenarios/tacklecontainer_fishing","title":"Tacklecontainer Fishing","description":"Populates a fishing tackle container with randomized fishing bobbers and lures upon creation.","permalink":"/dst-api-webdocs/docs/game-scripts/scenarios/tacklecontainer_fishing"},{"id":"game-scripts/prefabs/treasurechest","title":"Treasurechest","description":"Implements a modular chest prefab factory with variant-specific behavior for treasure storage, looting, upgrading, and special interactions.","permalink":"/dst-api-webdocs/docs/game-scripts/prefabs/treasurechest"},{"id":"game-scripts/components/unwrappable","title":"Unwrappable","description":"Manages the ability for an entity (such as a bundle or gift box) to be unwrapped, storing wrapped items and defining behavior during unwrap actions.","permalink":"/dst-api-webdocs/docs/game-scripts/components/unwrappable"}],"unlisted":false}}')}}]);